   537→				buildEvtResHandler(at, gvk, strings.Title(gvr.Resource)),
   538→			); err != nil {
   539→				return err
   540→			}
   541→			handlers = append(handlers, handlerRegistration)
   542→		}
   543→	}
   544→	sched.registeredHandlers = handlers
